import { Link } from "react-router-dom"


const Completedones = ({ indata }) => {

  if (!indata) return <div>Loading...</div>;

  const completed = indata.filter(task => task.status === "Completed");

  return (
    <div>
      {completed.map(task => (
        <p key={task.id}>{task.task}</p>
      ))}
    </div>
  );
};

export default Completedones
